// Get raw input from webhook
const raw = $input.first().json;

// Webhook may store data in body
const input = raw.body ? raw.body : raw;

// Debug logging
console.log('RAW INPUT:', JSON.stringify(raw, null, 2));
console.log('PARSED INPUT:', JSON.stringify(input, null, 2));

// Ensure vulnerabilities is array
let vulnerabilities = [];
if (Array.isArray(input.vulnerabilities)) {
  vulnerabilities = input.vulnerabilities;
} else if (input.vulnerabilities) {
  vulnerabilities = [input.vulnerabilities];
}

// Ensure codeSnippets is array
let codeSnippets = [];
if (Array.isArray(input.codeSnippets)) {
  codeSnippets = input.codeSnippets;
} else if (input.codeSnippets) {
  codeSnippets = [input.codeSnippets];
}

// Debug values
console.log('VULNERABILITIES:', vulnerabilities);
console.log('REPOSITORY:', input.repository);

return [{
  json: {
    repository: input.repository || 'unknown',
    branch: input.branch || 'main',
    commit: input.commit || input.commitHash || 'unknown',
    scanResults: input.scanResults || 'Security scan completed',
    vulnerabilities: vulnerabilities,
    codeSnippets: codeSnippets,
    timestamp: new Date().toISOString()
  }
}];

// Build detailed security analysis prompt
const data = $input.all()[0].json;

// Count vulnerabilities by severity
const severityCounts = {
  CRITICAL: 0,
  HIGH: 0,
  MEDIUM: 0,
  LOW: 0
};

data.vulnerabilities.forEach(vuln => {
  const severity = (vuln.severity || 'UNKNOWN').toUpperCase();
  if (severityCounts[severity] !== undefined) {
    severityCounts[severity]++;
  }
});

// Build prompt in Kazakh
const prompt = `Сіз қауіпсіздік талдауын жүргізетін киберқауіпсіздік сарапшысысыз.

=== ҚАУІПСІЗДІК СКАНЕРІ ЕСЕБІ ===

Репозиторий: ${data.repository}
Тармақ: ${data.branch}
Коммит: ${data.commit}

Сканер қорытындысы: ${data.scanResults}

=== ТАБЫЛҒАН ОСАЛДЫҚТАР ===
Барлығы: ${data.vulnerabilities.length}
- CRITICAL (Өте қауіпті): ${severityCounts.CRITICAL}
- HIGH (Жоғары): ${severityCounts.HIGH}
- MEDIUM (Орташа): ${severityCounts.MEDIUM}
- LOW (Төмен): ${severityCounts.LOW}

Толық ақпарат:
${JSON.stringify(data.vulnerabilities, null, 2)}

=== ҚАУІПТІ КОД ҮЛГІЛЕРІ ===
${data.codeSnippets.length > 0 ? JSON.stringify(data.codeSnippets, null, 2) : 'Табылмады'}

=== СІЗДІҢ ТАПСЫРМАҢЫЗ ===

Бұл қауіпсіздік есебін талдап, орналастыру туралы шешім қабылдаңыз.

ЕРЕЖЕЛЕР:
1. Егер CRITICAL немесе HIGH деңгейдегі осалдықтар болса → deployDecision "NO" болуы КЕРЕК
2. Егер қауіпті код үлгілері табылса (eval, exec, innerHTML) → deployDecision "NO" болуы КЕРЕК
3. Тек қауіпсіздік қатерлері болмаса ғана орналастыруға рұқсат беріңіз
4. Қауіпсіздікті басымдыққа алыңыз

ТЕК ҚАНА JSON форматында жауап беріңіз (markdown жоқ, түсініктеме жоқ):

{
  "deployDecision": "YES" немесе "NO",
  "riskLevel": "CRITICAL" немесе "HIGH" немесе "MEDIUM" немесе "LOW",
  "confidence": 0.95,
  "criticalIssues": ["нақты мәселе 1", "нақты мәселе 2"],
  "recommendations": ["нақты ұсыныс 1", "нақты ұсыныс 2"],
  "summary": "Қауіпсіздік бағалауының қысқаша қорытындысы"
}

МАҢЫЗДЫ: Барлық мәтінді ҚАЗАҚ ТІЛІНДЕ жазыңыз!`;

return [{
  json: {
    chatInput: prompt,
    originalData: data,
    severityCounts: severityCounts
  }
}];

// Parse AI response and build final decision
const originalData = $('Build AI Prompt').item.json.originalData;
const severityCounts = $('Build AI Prompt').item.json.severityCounts;
const startTime = originalData.timestamp;
const endTime = new Date().toISOString();
const processingTime = new Date(endTime) - new Date(startTime);

const aiResponse = $input.all()[0].json;

let analysis;

try {
  // Get AI response
  const responseText = aiResponse.output || aiResponse.text || aiResponse.response || JSON.stringify(aiResponse);

  // Extract JSON
  const jsonMatch = responseText.match(/\{[\s\S]*\}/);

  if (jsonMatch) {
    analysis = JSON.parse(jsonMatch[0]);
  } else {
    // Fallback
    const textLower = responseText.toLowerCase();
    const hasNo = textLower.includes('no') || textLower.includes('жоқ') || textLower.includes('бұғатталды');

    analysis = {
      deployDecision: hasNo ? 'NO' : 'YES',
      riskLevel: hasNo ? 'HIGH' : 'MEDIUM',
      confidence: 0.6,
      criticalIssues: ['AI жауабын талдау мүмкін болмады'],
      recommendations: ['Қолмен тексеру ұсынылады'],
      summary: responseText.substring(0, 200)
    };
  }
} catch (error) {
  analysis = {
    deployDecision: 'NO',
    riskLevel: 'CRITICAL',
    confidence: 0.0,
    criticalIssues: ['AI талдауы сәтсіз аяқталды: ' + error.message],
    recommendations: ['Қолмен қауіпсіздік тексеруі қажет'],
    summary: 'Қауіпсіздік талдауында қате орын алды'
  };
}

// Validate fields
analysis.deployDecision = analysis.deployDecision || 'NO';
analysis.riskLevel = analysis.riskLevel || 'БЕЛГІСІЗ';
analysis.confidence = typeof analysis.confidence === 'number' ? analysis.confidence : 0.5;
analysis.criticalIssues = Array.isArray(analysis.criticalIssues) ? analysis.criticalIssues : [];
analysis.recommendations = Array.isArray(analysis.recommendations) ? analysis.recommendations : [];
analysis.summary = analysis.summary || 'Талдау аяқталды';

return [{
  json: {
    success: true,
    deployDecision: analysis.deployDecision,
    riskLevel: analysis.riskLevel,
    confidence: analysis.confidence,
    criticalIssues: analysis.criticalIssues,
    recommendations: analysis.recommendations,
    summary: analysis.summary,
    processingTimeMs: processingTime,
    timestamp: endTime,
    aiProvider: 'Google Gemini LangChain Agent',
    scanStatistics: {
      totalVulnerabilities: originalData.vulnerabilities.length,
      criticalCount: severityCounts.CRITICAL,
      highCount: severityCounts.HIGH,
      mediumCount: severityCounts.MEDIUM,
      lowCount: severityCounts.LOW,
      dangerousPatterns: originalData.codeSnippets.length
    },
    metadata: {
      repository: originalData.repository,
      branch: originalData.branch,
      commit: originalData.commit
    }
  }
}];
